    val message = payload.message.ifBlank { entry?.message ?: "API error $code" }
    val toast = payload.toast
    return ApiErrorPayload(
        id = payload.id.ifBlank { entry?.id.orEmpty() },
        group = payload.group.ifBlank { entry?.group.orEmpty() },
        key = payload.key.ifBlank { entry?.key.orEmpty() },
        code = code,
        message = message,
        toast = ApiToastPayload(
            key = toast.key.ifBlank { entry?.toast?.key.orEmpty() },
            level = toast.level.ifBlank { entry?.toast?.level ?: "error" },
            default = toast.default.ifBlank { entry?.toast?.default ?: message },
            text = toast.text,
        ),
    )
}

